functions.functionContent:
{
    //
    // Check the arguments.
    //
    ASSERT(CMPSSLITE_isBaseValid(base));

    //
    // Write the DAC configuration to the appropriate register.
    //
    EALLOW;

    HWREGH(base + CMPSSLITE_O_COMPDACHCTL) =
                                     (HWREGH(base + CMPSSLITE_O_COMPDACHCTL) &
                                      ~CMPSSLITE_COMPDACHCTL_SWLOADSEL)      |
                                     config;

    EDIS;
}
